export type Asset = {
	id: string;
	filename: string;
	originalName: string;
	mimeType: string;
	size: number;
	url: string;
	folderId?: string;
	alt?: string;
	createdAt: Date;
};

export type Folder = {
	id: string;
	name: string;
	parentId?: string;
	createdAt: Date;
};

export interface SerializedAsset extends Omit<Asset, "createdAt"> {
	createdAt: string;
}

export interface SerializedFolder extends Omit<Folder, "createdAt"> {
	createdAt: string;
}

import { z } from "zod";

export const AssetListQuerySchema = z.object({
	folderId: z.string().optional(),
	mimeType: z.string().optional(),
	query: z.string().optional(),
	offset: z.coerce.number().int().min(0).optional(),
	limit: z.coerce.number().int().min(1).max(100).optional(),
});

export const createAssetSchema = z.object({
	filename: z.string().min(1),
	originalName: z.string().min(1),
	mimeType: z.string().min(1),
	// Allow 0 for URL-registered assets where size is unknown at registration time.
	size: z.number().int().min(0),
	url: z.httpUrl(),
	folderId: z.string().optional(),
	alt: z.string().optional(),
});

export const updateAssetSchema = z.object({
	alt: z.string().optional(),
	folderId: z.string().nullable().optional(),
});

export const createFolderSchema = z.object({
	name: z.string().min(1),
	parentId: z.string().optional(),
});

export const uploadTokenRequestSchema = z.object({
	filename: z.string().min(1),
	mimeType: z.string().min(1),
	size: z.number().int().positive(),
	folderId: z.string().optional(),
});

import { useDeleteAsset } from "@btst/stack/plugins/media/client/hooks";
import type { SerializedAsset } from "../../../types";
import { cn } from "@/lib/utils";
import { File, Check, Copy, Trash2 } from "lucide-react";
import { isImage, formatBytes } from "./utils";
import { usePluginOverrides } from "@btst/stack/context";
import type { MediaPluginOverrides } from "../../overrides";
import { AssetPreviewButton } from "./asset-preview-button";
import { toast } from "sonner";

export function AssetCard({
	asset,
	onToggle,
	selected = false,
	onDelete,
	apiBaseURL,
}: {
	asset: SerializedAsset;
	selected?: boolean;
	onToggle?: () => void;
	onDelete?: (id: string) => void | Promise<void>;
	apiBaseURL?: string;
}) {
	const { mutateAsync: deleteAsset } = useDeleteAsset();
	const { Image: ImageComponent } = usePluginOverrides<
		MediaPluginOverrides,
		Partial<MediaPluginOverrides>
	>("media", {});
	const imageAsset = isImage(asset.mimeType);
	const selectable = typeof onToggle === "function";

	const copyUrl = () => {
		let fullUrl: string;
		try {
			fullUrl = new URL(asset.url, apiBaseURL).href;
		} catch {
			fullUrl = asset.url;
		}
		navigator.clipboard
			.writeText(fullUrl)
			.then(() => toast.success("URL copied"));
	};

	const handleDelete = () => {
		if (onDelete) {
			return onDelete(asset.id);
		}

		if (confirm(`Delete "${asset.originalName}"?`)) {
			return deleteAsset(asset.id).catch(console.error);
		}
	};

	return (
		<div
			role={selectable ? "button" : undefined}
			tabIndex={selectable ? 0 : undefined}
			data-testid="media-asset-item"
			onClick={onToggle}
			onKeyDown={(e) => {
				if (selectable && (e.key === "Enter" || e.key === " ")) {
					e.preventDefault();
					onToggle();
				}
			}}
			className={cn(
				"group relative cursor-pointer rounded-md border bg-muted/30 p-1 transition-all hover:border-ring hover:shadow-sm",
				!selectable && "cursor-default",
				selected && "border-ring ring-1 ring-ring",
			)}
		>
			{/* Thumbnail */}
			<div className="flex h-28 items-center justify-center overflow-hidden rounded bg-muted">
				{imageAsset ? (
					ImageComponent ? (
						<ImageComponent
							src={asset.url}
							alt={asset.alt || asset.originalName}
							className="h-full w-full object-cover"
							width={160}
							height={80}
						/>
					) : (
						<img
							src={asset.url}
							alt={asset.alt || asset.originalName}
							className="h-full w-full object-cover"
							loading="lazy"
						/>
					)
				) : (
					<File className="size-8 text-muted-foreground" />
				)}
			</div>

			{/* Name + size */}
			<div className="mt-1 px-0.5">
				<p
					className="truncate text-xs font-medium leading-tight"
					title={asset.originalName}
				>
					{asset.originalName}
				</p>
				<p className="text-[10px] text-muted-foreground">
					{formatBytes(asset.size)}
				</p>
			</div>

			{/* Selection indicator */}
			{selected && (
				<div className="absolute right-1 top-1 rounded-full bg-primary p-0.5 text-primary-foreground">
					<Check className="size-3" />
				</div>
			)}

			<div className="absolute right-1 top-1 hidden gap-1 group-hover:flex">
				{apiBaseURL ? (
					<button
						type="button"
						title="Copy URL"
						onClick={(e) => {
							e.stopPropagation();
							copyUrl();
						}}
						className="rounded bg-background/80 p-0.5 shadow hover:bg-background"
					>
						<Copy className="size-3" />
					</button>
				) : null}
				{imageAsset ? (
					<AssetPreviewButton
						asset={asset}
						className="rounded bg-background/80 p-0.5 shadow hover:bg-background"
					/>
				) : null}
				<button
					type="button"
					title="Delete"
					onClick={(e) => {
						e.stopPropagation();
						void handleDelete();
					}}
					className="rounded bg-destructive/80 p-0.5 text-white hover:bg-destructive"
				>
					<Trash2 className="size-3" />
				</button>
			</div>
		</div>
	);
}

"use client";

import { useState } from "react";
import {
	Dialog,
	DialogClose,
	DialogContent,
	DialogHeader,
	DialogTitle,
} from "@/components/ui/dialog";
import { Eye, X } from "lucide-react";
import type { SerializedAsset } from "../../../types";

export function AssetPreviewButton({
	asset,
	className,
}: {
	asset: SerializedAsset;
	className: string;
}) {
	const [open, setOpen] = useState(false);

	return (
		<>
			<button
				type="button"
				title="Preview"
				aria-label={`Preview ${asset.originalName}`}
				onClick={(event) => {
					event.stopPropagation();
					setOpen(true);
				}}
				className={className}
			>
				<Eye className="size-3" />
			</button>

			<Dialog open={open} onOpenChange={setOpen}>
				<DialogContent
					showCloseButton={false}
					className="h-screen w-screen max-w-none border-0 bg-black/95 p-4 shadow-none sm:max-w-none sm:rounded-none sm:p-6"
				>
					<DialogHeader className="sr-only">
						<DialogTitle>{asset.alt || asset.originalName}</DialogTitle>
					</DialogHeader>

					<DialogClose
						className="absolute right-4 top-4 z-10 rounded bg-black/60 p-2 text-white transition hover:bg-black/80"
						aria-label="Close preview"
					>
						<X className="size-4" />
					</DialogClose>

					<div className="h-full w-full overflow-auto">
						<div className="flex min-h-full w-full items-start justify-center">
							<img
								src={asset.url}
								alt={asset.alt || asset.originalName}
								className="block h-auto w-auto max-w-none"
							/>
						</div>
					</div>
				</DialogContent>
			</Dialog>
		</>
	);
}

import { useState, useRef } from "react";
import { useAssets } from "@btst/stack/plugins/media/client/hooks";
import type { SerializedAsset } from "../../../types";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Loader2, Search, X, Image } from "lucide-react";
import { AssetCard } from "./asset-card";
import { matchesAccept } from "./utils";

export function BrowseTab({
	folderId,
	selected = [],
	accept,
	onToggle,
	onDelete,
	apiBaseURL,
	emptyMessage = "No files found",
}: {
	folderId: string | null;
	selected?: SerializedAsset[];
	accept?: string[];
	onToggle?: (asset: SerializedAsset) => void;
	onDelete?: (id: string) => void | Promise<void>;
	apiBaseURL?: string;
	emptyMessage?: string;
}) {
	const [search, setSearch] = useState("");
	const [debouncedSearch, setDebouncedSearch] = useState("");
	const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
	const selectable = typeof onToggle === "function";

	const handleSearch = (v: string) => {
		setSearch(v);
		if (debounceRef.current) clearTimeout(debounceRef.current);
		debounceRef.current = setTimeout(() => setDebouncedSearch(v), 300);
	};

	const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } =
		useAssets({
			folderId: folderId ?? undefined,
			query: debouncedSearch || undefined,
			limit: 40,
		});

	const allAssets = data?.pages.flatMap((p) => p.items) ?? [];
	const filtered = accept
		? allAssets.filter((a) => matchesAccept(a.mimeType, accept))
		: allAssets;

	return (
		<div className="flex h-full min-h-0 flex-col gap-2">
			<div className="relative">
				<Search className="absolute left-2 top-1/2 size-3.5 -translate-y-1/2 text-muted-foreground" />
				<Input
					value={search}
					onChange={(e) => handleSearch(e.target.value)}
					placeholder="Search files…"
					className="h-8 pl-7 text-sm"
				/>
				{search && (
					<button
						type="button"
						onClick={() => {
							setSearch("");
							setDebouncedSearch("");
						}}
						className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
					>
						<X className="size-3.5" />
					</button>
				)}
			</div>

			{isLoading ? (
				<div className="flex flex-1 items-center justify-center">
					<Loader2 className="size-6 animate-spin text-muted-foreground" />
				</div>
			) : filtered.length === 0 ? (
				<div className="flex flex-1 flex-col items-center justify-center gap-2 text-sm text-muted-foreground">
					<Image className="size-8" />
					<p>{emptyMessage}</p>
				</div>
			) : (
				<div className="flex-1 overflow-y-auto overscroll-contain">
					<div className="grid grid-cols-2 gap-2 pb-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
						{filtered.map((asset) => (
							<AssetCard
								key={asset.id}
								asset={asset}
								selected={selected.some((s) => s.id === asset.id)}
								onToggle={selectable ? () => onToggle(asset) : undefined}
								onDelete={onDelete}
								apiBaseURL={apiBaseURL}
							/>
						))}
					</div>
					{hasNextPage && (
						<div className="flex justify-center py-2">
							<Button
								variant="ghost"
								size="sm"
								onClick={() => fetchNextPage()}
								disabled={isFetchingNextPage}
							>
								{isFetchingNextPage ? (
									<Loader2 className="mr-1 size-3 animate-spin" />
								) : null}
								Load more
							</Button>
						</div>
					)}
				</div>
			)}
		</div>
	);
}

import { useState } from "react";
import {
	useFolders,
	useCreateFolder,
	useDeleteFolder,
} from "@btst/stack/plugins/media/client/hooks";
import type { SerializedFolder } from "../../../types";
import { FolderPlus } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Check, Folder, Trash2, ChevronRight, FolderOpen } from "lucide-react";
import { cn } from "@/lib/utils";

export function FolderTree({
	selectedId,
	onSelect,
}: {
	selectedId: string | null;
	onSelect: (id: string | null) => void;
}) {
	const { data: rootFoldersRaw = [] } = useFolders(null);
	const rootFolders =
		rootFoldersRaw as import("../../../types").SerializedFolder[];
	const [newFolderName, setNewFolderName] = useState("");
	const [isCreating, setIsCreating] = useState(false);
	const { mutateAsync: createFolder } = useCreateFolder();
	const { mutateAsync: deleteFolder } = useDeleteFolder();

	const handleCreateFolder = async () => {
		const name = newFolderName.trim();
		if (!name) return;
		try {
			await createFolder({ name, parentId: selectedId ?? undefined });
			setNewFolderName("");
			setIsCreating(false);
		} catch (err) {
			console.error("[btst/media] Failed to create folder", err);
		}
	};

	return (
		<div className="flex h-full min-h-0 flex-col">
			<div className="flex items-center justify-between px-2 py-2">
				<span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
					Folders
				</span>
				<button
					type="button"
					title="New folder"
					onClick={() => setIsCreating((v) => !v)}
					className="rounded p-0.5 hover:bg-muted"
				>
					<FolderPlus className="size-3.5 text-muted-foreground" />
				</button>
			</div>

			{isCreating && (
				<div className="flex gap-1 px-2 pb-1">
					<Input
						autoFocus
						value={newFolderName}
						onChange={(e) => setNewFolderName(e.target.value)}
						placeholder="Folder name"
						className="h-6 text-xs"
						onKeyDown={(e) => {
							if (e.key === "Enter") void handleCreateFolder();
							if (e.key === "Escape") setIsCreating(false);
						}}
					/>
					<button
						type="button"
						onClick={handleCreateFolder}
						className="rounded px-1 py-0.5 text-xs hover:bg-muted"
					>
						<Check className="size-3" />
					</button>
				</div>
			)}

			<div className="flex-1 overflow-y-auto overscroll-contain">
				{/* All assets (root) */}
				<button
					type="button"
					onClick={() => onSelect(null)}
					className={cn(
						"flex w-full items-center gap-1.5 rounded px-2 py-1 text-left text-sm hover:bg-muted",
						selectedId === null && "bg-muted font-medium",
					)}
				>
					<span className="size-3" />
					<Folder className="size-3.5 shrink-0 text-muted-foreground" />
					<span className="truncate">All files</span>
				</button>

				{rootFolders.map((folder) => (
					<FolderTreeItem
						key={folder.id}
						folder={folder}
						selectedId={selectedId}
						onSelect={onSelect}
					/>
				))}
			</div>

			{selectedId && (
				<div className="border-t px-2 py-1">
					<button
						type="button"
						onClick={async () => {
							if (
								confirm("Delete this folder? Assets inside will be unaffected.")
							) {
								try {
									await deleteFolder(selectedId);
									onSelect(null);
								} catch (err) {
									console.error("[btst/media] Failed to delete folder", err);
								}
							}
						}}
						className="flex items-center gap-1 text-xs text-destructive hover:underline"
					>
						<Trash2 className="size-3" />
						Delete folder
					</button>
				</div>
			)}
		</div>
	);
}

export function FolderTreeItem({
	folder,
	selectedId,
	onSelect,
	depth = 0,
}: {
	folder: SerializedFolder;
	selectedId: string | null;
	onSelect: (id: string | null) => void;
	depth?: number;
}) {
	const [expanded, setExpanded] = useState(false);
	const { data: children = [] } = useFolders(folder.id);

	return (
		<div>
			<button
				type="button"
				onClick={() => {
					onSelect(folder.id);
					setExpanded((v) => !v);
				}}
				className={cn(
					"flex w-full items-center gap-1.5 rounded px-2 py-1 text-left text-sm hover:bg-muted",
					selectedId === folder.id && "bg-muted font-medium",
				)}
				style={{ paddingLeft: `${8 + depth * 12}px` }}
			>
				{children.length > 0 ? (
					<ChevronRight
						className={cn(
							"size-3 shrink-0 transition-transform",
							expanded && "rotate-90",
						)}
					/>
				) : (
					<span className="size-3" />
				)}
				{expanded ? (
					<FolderOpen className="size-3.5 shrink-0 text-amber-500" />
				) : (
					<Folder className="size-3.5 shrink-0 text-amber-500" />
				)}
				<span className="truncate">{folder.name}</span>
			</button>
			{expanded &&
				children.map((child) => (
					<FolderTreeItem
						key={child.id}
						folder={child}
						selectedId={selectedId}
						onSelect={onSelect}
						depth={depth + 1}
					/>
				))}
		</div>
	);
}

"use client";
import { useState, type ReactNode } from "react";
import {
	Popover,
	PopoverContent,
	PopoverTrigger,
} from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import {
	Tabs,
	TabsContent,
	TabsList,
	TabsTrigger,
} from "@/components/ui/tabs";
import { Image, Upload, Link, X } from "lucide-react";
import type { SerializedAsset } from "../../../types";
import { FolderTree } from "./folder-tree";
import { BrowseTab } from "./browse-tab";
import { UploadTab } from "./upload-tab";
import { UrlTab } from "./url-tab";
import type { MediaPluginOverrides } from "../../overrides";
import { usePluginOverrides } from "@btst/stack/context";

export interface MediaPickerProps {
	/**
	 * Element that triggers opening the picker. Required.
	 */
	trigger: ReactNode;
	/**
	 * Called when the user confirms their selection.
	 */
	onSelect: (assets: SerializedAsset[]) => void;
	/**
	 * Allow multiple selection.
	 * @default false
	 */
	multiple?: boolean;
	/**
	 * Filter displayed assets by MIME type prefix (e.g. "image/").
	 */
	accept?: string[];
}

/**
 * MediaPicker — a Popover-based media browser.
 *
 * Reads API config from the `media` plugin overrides context (set up in StackProvider).
 * Must be rendered inside a `StackProvider` that includes media overrides.
 *
 * @example
 * ```tsx
 * <MediaPicker
 *   trigger={<Button size="sm">Browse media</Button>}
 *   accept={["image/*"]}
 *   onSelect={(assets) => form.setValue("image", assets[0].url)}
 * />
 * ```
 */
export function MediaPicker({
	trigger,
	onSelect,
	multiple = false,
	accept,
}: MediaPickerProps) {
	const [open, setOpen] = useState(false);
	const [selectedFolder, setSelectedFolder] = useState<string | null>(null);
	const [selectedAssets, setSelectedAssets] = useState<SerializedAsset[]>([]);
	const [activeTab, setActiveTab] = useState<"browse" | "upload" | "url">(
		"browse",
	);

	const handleClose = () => {
		setOpen(false);
		setSelectedAssets([]);
	};

	const handleConfirm = () => {
		if (selectedAssets.length === 0) return;
		// Copy selection before clearing; defer onSelect so the popover has time
		// to start its close animation before any parent state updates that might
		// unmount this component (e.g. CMSFileUpload hiding when previewUrl is set).
		const toSelect = [...selectedAssets];
		handleClose();
		setTimeout(() => onSelect(toSelect), 0);
	};

	const handleToggleAsset = (asset: SerializedAsset) => {
		if (multiple) {
			setSelectedAssets((prev) =>
				prev.some((a) => a.id === asset.id)
					? prev.filter((a) => a.id !== asset.id)
					: [...prev, asset],
			);
		} else {
			setSelectedAssets([asset]);
		}
	};

	const handleUploaded = (asset: SerializedAsset) => {
		if (multiple) {
			setSelectedAssets((prev) => [...prev, asset]);
		} else {
			setSelectedAssets([asset]);
			setActiveTab("browse");
		}
	};

	const handleUrlRegistered = (asset: SerializedAsset) => {
		// Close the popover first, then notify parent — same deferral as handleConfirm.
		const toSelect = asset;
		handleClose();
		setTimeout(() => onSelect([toSelect]), 0);
	};

	return (
		<Popover
			open={open}
			onOpenChange={(v) => {
				if (!v) handleClose();
				else setOpen(true);
			}}
		>
			<PopoverTrigger asChild>{trigger}</PopoverTrigger>
			<PopoverContent
				className="w-[calc(100vw-1rem)] max-w-[calc(100vw-1rem)] overflow-hidden p-0 sm:w-[900px]"
				align="start"
				sideOffset={8}
				collisionPadding={8}
				style={{
					maxWidth: "min(900px, calc(100vw - 1rem))",
					height: "min(720px, calc(100dvh - 1rem))",
				}}
			>
				<div className="flex h-full flex-col overflow-hidden rounded-md">
					{/* Header */}
					<div className="flex items-center justify-between border-b px-3 py-2">
						<span className="text-sm font-semibold">Media Library</span>
						<button
							type="button"
							onClick={handleClose}
							className="rounded p-0.5 hover:bg-muted"
						>
							<X className="size-4" />
						</button>
					</div>

					{/* Body */}
					<div className="flex min-h-0 flex-1 flex-col md:flex-row">
						{/* Folder sidebar */}
						<div className="max-h-40 w-full shrink-0 overflow-hidden border-b bg-muted/20 md:max-h-none md:w-44 md:border-b-0 md:border-r">
							<FolderTree
								selectedId={selectedFolder}
								onSelect={setSelectedFolder}
							/>
						</div>

						{/* Main panel */}
						<div className="flex min-w-0 flex-1 flex-col p-3 overflow-y-hidden">
							<Tabs
								value={activeTab}
								onValueChange={(v) => setActiveTab(v as any)}
								className="flex flex-1 flex-col min-h-0"
							>
								<TabsList className="grid h-auto w-full shrink-0 grid-cols-3 md:flex md:w-fit">
									<TabsTrigger
										value="browse"
										className="h-8 px-2 text-xs md:h-6 md:px-3"
									>
										<Image className="mr-1 size-3" />
										Browse
									</TabsTrigger>
									<TabsTrigger
										value="upload"
										className="h-8 px-2 text-xs md:h-6 md:px-3"
									>
										<Upload className="mr-1 size-3" />
										Upload
									</TabsTrigger>
									<TabsTrigger
										value="url"
										className="h-8 px-2 text-xs md:h-6 md:px-3"
									>
										<Link className="mr-1 size-3" />
										URL
									</TabsTrigger>
								</TabsList>

								<div className="mt-2 min-h-0 flex-1">
									<TabsContent
										value="browse"
										className="m-0 h-full min-h-0 data-[state=active]:flex data-[state=active]:flex-col"
									>
										<BrowseTab
											folderId={selectedFolder}
											selected={selectedAssets}
											accept={accept}
