import { useState, useCallback, useRef } from "react";
import { useUploadAsset } from "@btst/stack/plugins/media/client/hooks";
import type { SerializedAsset } from "../../../types";
import { Button } from "@/components/ui/button";
import { Loader2, Upload } from "lucide-react";
import { cn } from "@/lib/utils";
import { matchesAccept } from "./utils";

export function UploadTab({
	folderId,
	accept,
	onUploaded,
}: {
	folderId: string | null;
	accept?: string[];
	onUploaded: (asset: SerializedAsset) => void;
}) {
	const [dragging, setDragging] = useState(false);
	const [uploading, setUploading] = useState(false);
	const [error, setError] = useState<string | null>(null);
	const fileInputRef = useRef<HTMLInputElement>(null);
	const { mutateAsync: uploadAsset } = useUploadAsset();

	const acceptAttr = accept?.join(",") ?? undefined;

	const handleFiles = useCallback(
		async (files: FileList | File[]) => {
			const fileArr = Array.from(files);
			if (fileArr.length === 0) return;
			setError(null);
			setUploading(true);
			try {
				for (const file of fileArr) {
					if (accept && !matchesAccept(file.type, accept)) {
						setError(`File type ${file.type} is not accepted.`);
						continue;
					}
					const asset = await uploadAsset({
						file,
						folderId: folderId ?? undefined,
					});
					onUploaded(asset);
				}
			} catch (err) {
				setError(err instanceof Error ? err.message : "Upload failed");
			} finally {
				setUploading(false);
			}
		},
		[accept, folderId, uploadAsset, onUploaded],
	);

	return (
		<div className="flex h-full flex-col gap-3">
			<div
				onDragOver={(e) => {
					e.preventDefault();
					setDragging(true);
				}}
				onDragLeave={() => setDragging(false)}
				onDrop={(e) => {
					e.preventDefault();
					setDragging(false);
					void handleFiles(e.dataTransfer.files);
				}}
				className={cn(
					"flex flex-1 flex-col items-center justify-center gap-3 rounded-lg border-2 border-dashed px-4 py-6 text-center transition-colors sm:px-6",
					dragging ? "border-ring bg-ring/5" : "border-muted-foreground/30",
				)}
			>
				{uploading ? (
					<>
						<Loader2 className="size-8 animate-spin text-muted-foreground" />
						<p className="text-sm text-muted-foreground">Uploading…</p>
					</>
				) : (
					<>
						<Upload className="size-8 text-muted-foreground" />
						<div className="text-center">
							<p className="text-sm font-medium">Drop files here</p>
							<p className="text-xs text-muted-foreground">
								or click to browse
							</p>
						</div>
						<Button
							type="button"
							variant="outline"
							size="sm"
							onClick={() => fileInputRef.current?.click()}
						>
							Choose files
						</Button>
					</>
				)}
			</div>
			{error && <p className="text-sm text-destructive">{error}</p>}
			<input
				ref={fileInputRef}
				type="file"
				accept={acceptAttr}
				multiple
				className="hidden"
				data-testid="media-upload-input"
				onChange={(e) => e.target.files && handleFiles(e.target.files)}
			/>
		</div>
	);
}

import { useState } from "react";
import { useRegisterAsset } from "@btst/stack/plugins/media/client/hooks";
import type { SerializedAsset } from "../../../types";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Loader2, Check } from "lucide-react";

export function UrlTab({
	folderId,
	onRegistered,
}: {
	folderId: string | null;
	onRegistered: (asset: SerializedAsset) => void;
}) {
	const [url, setUrl] = useState("");
	const [error, setError] = useState<string | null>(null);
	const { mutateAsync: registerAsset, isPending } = useRegisterAsset();

	const handleSubmit = async (e: React.FormEvent) => {
		e.preventDefault();
		setError(null);
		const trimmed = url.trim();
		if (!trimmed) return;
		try {
			const filename = trimmed.split("/").pop() ?? "asset";
			const asset = await registerAsset({
				url: trimmed,
				filename,
				folderId: folderId ?? undefined,
			});
			setUrl("");
			onRegistered(asset);
		} catch (err) {
			setError(err instanceof Error ? err.message : "Failed to register URL");
		}
	};

	return (
		<div className="flex h-full flex-col gap-3 pt-2">
			<p className="text-sm text-muted-foreground">
				Paste a public URL to register it as an asset without uploading a file.
			</p>
			<form onSubmit={handleSubmit} className="flex flex-col gap-2">
				<div className="flex flex-col gap-2 sm:flex-row">
					<Input
						type="url"
						value={url}
						onChange={(e) => setUrl(e.target.value)}
						placeholder="https://example.com/image.png"
						className="flex-1"
						data-testid="media-url-input"
						autoFocus
					/>
					<Button
						type="submit"
						size="sm"
						disabled={isPending || !url.trim()}
						className="w-full sm:w-auto"
					>
						{isPending ? (
							<Loader2 className="mr-1 size-4 animate-spin" />
						) : (
							<Check className="mr-1 size-4" />
						)}
						Use URL
					</Button>
				</div>
				{error && <p className="text-sm text-destructive">{error}</p>}
			</form>
		</div>
	);
}

export function matchesAccept(mimeType: string, accept?: string[]) {
	if (!accept || accept.length === 0) return true;
	return accept.some((a) => {
		if (a.endsWith("/*")) return mimeType.startsWith(a.slice(0, -1));
		return mimeType === a;
	});
}

export function isImage(mimeType: string) {
	return mimeType.startsWith("image/");
}

export function formatBytes(bytes: number) {
	if (bytes < 1024) return `${bytes} B`;
	if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
	return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
}

