import type { ComponentType } from "react";
import type { QueryClient } from "@tanstack/react-query";
import type { ImageCompressionOptions } from "./utils/image-compression";

/**
 * Upload mode — must match the storage adapter configured in mediaBackendPlugin.
 * - `"direct"` — local filesystem adapter, files are uploaded via `POST /media/upload`
 * - `"s3"` — AWS S3 / R2 / MinIO, the client fetches a presigned token then PUTs directly to S3
 * - `"vercel-blob"` — Vercel Blob, uses the `@vercel/blob/client` SDK for direct upload
 */
export type MediaUploadMode = "direct" | "s3" | "vercel-blob";

/**
 * Overridable components and functions for the Media plugin.
 *
 * External consumers provide these when registering the media client plugin
 * via the StackProvider overrides.
 */
export interface MediaPluginOverrides {
	/**
	 * Base URL for API calls (e.g., "http://localhost:3000").
	 */
	apiBaseURL: string;

	/**
	 * Path where the API is mounted (e.g., "/api/data").
	 */
	apiBasePath: string;

	/**
	 * React Query client — used by the MediaPicker to cache and fetch assets.
	 */
	queryClient: QueryClient;

	/**
	 * Upload mode — must match the storageAdapter configured in mediaBackendPlugin.
	 * @default "direct"
	 */
	uploadMode?: MediaUploadMode;

	/**
	 * Optional headers to pass with API requests (e.g., for SSR auth).
	 */
	headers?: HeadersInit;

	/**
	 * Navigation function for programmatic navigation.
	 */
	navigate: (path: string) => void | Promise<void>;

	/**
	 * Link component for navigation within the media library page.
	 */
	Link?: ComponentType<React.ComponentProps<"a"> & Record<string, any>>;

	/**
	 * Image component for rendering asset thumbnails and previews.
	 *
	 * When provided, replaces the default `<img>` element in asset cards,
	 * the media library grid, and the ImageInputField preview. Use this
	 * to plug in Next.js `<Image>` for automatic optimisation.
	 *
	 * @example
	 * ```tsx
	 * Image: (props) => <NextImage {...props} />
	 * ```
	 */
	Image?: ComponentType<
		React.ImgHTMLAttributes<HTMLImageElement> & Record<string, any>
	>;

	/**
	 * Client-side image compression applied before upload via the Canvas API.
	 *
	 * Images are scaled down to fit within `maxWidth` × `maxHeight` (preserving
	 * aspect ratio) and re-encoded at `quality`. SVG and GIF files are always
	 * passed through unchanged.
	 *
	 * Set to `false` to disable compression entirely.
	 *
	 * @default { maxWidth: 2048, maxHeight: 2048, quality: 0.85 }
	 */
	imageCompression?: ImageCompressionOptions | false;

	// ============ Lifecycle Hooks ============

	/**
	 * Called when a media route is rendered.
	 */
	onRouteRender?: (
		routeName: string,
		context: MediaRouteContext,
	) => void | Promise<void>;

	/**
	 * Called when a media route encounters an error.
	 */
	onRouteError?: (
		routeName: string,
		error: Error,
		context: MediaRouteContext,
	) => void | Promise<void>;

	/**
	 * Called before the media library page is rendered.
	 * Return `false` to prevent rendering (e.g., redirect unauthenticated users).
	 *
	 * @example
	 * ```ts
	 * media: {
	 *   onBeforeLibraryPageRendered: (context) => !!currentUser?.isAdmin,
	 *   onRouteError: (routeName, error, context) => navigate("/login"),
	 * }
	 * ```
	 */
	onBeforeLibraryPageRendered?: (context: MediaRouteContext) => boolean;
}

export interface MediaRouteContext {
	/** Current route path */
	path: string;
	/** Route parameters */
	params?: Record<string, string>;
	/** Whether rendering on server (true) or client (false) */
	isSSR: boolean;
	[key: string]: unknown;
}

"use client";

import type { SerializedAsset } from "../types";
import type { MediaPluginOverrides } from "./overrides";
import { compressImage } from "./utils/image-compression";

export type MediaUploadClientConfig = Pick<
	MediaPluginOverrides,
	"apiBaseURL" | "apiBasePath" | "headers" | "uploadMode" | "imageCompression"
>;

export interface UploadAssetInput {
	file: File;
	folderId?: string;
}

const DEFAULT_IMAGE_COMPRESSION = {
	maxWidth: 2048,
	maxHeight: 2048,
	quality: 0.85,
} as const;

/**
 * Upload an asset using the media plugin's configured storage mode.
 *
 * Use this in non-React contexts like editor `uploadImage` callbacks. React
 * components should usually prefer `useUploadAsset()`, which wraps this helper
 * and handles cache invalidation.
 */
export async function uploadAsset(
	config: MediaUploadClientConfig,
	input: UploadAssetInput,
): Promise<SerializedAsset> {
	const {
		apiBaseURL,
		apiBasePath,
		headers,
		uploadMode = "direct",
		imageCompression,
	} = config;
	const { file, folderId } = input;

	const processedFile =
		imageCompression === false
			? file
			: await compressImage(
					file,
					imageCompression ?? DEFAULT_IMAGE_COMPRESSION,
				);

	const base = `${apiBaseURL}${apiBasePath}`;
	const headersObj = new Headers(headers as HeadersInit | undefined);

	if (uploadMode === "direct") {
		const formData = new FormData();
		formData.append("file", processedFile);
		if (folderId) formData.append("folderId", folderId);

		const res = await fetch(`${base}/media/upload`, {
			method: "POST",
			headers: headersObj,
			body: formData,
		});
		if (!res.ok) {
			const err = await res.json().catch(() => ({ message: res.statusText }));
			throw new Error(err.message ?? "Upload failed");
		}
		return res.json();
	}

	if (uploadMode === "s3") {
		const tokenRes = await fetch(`${base}/media/upload/token`, {
			method: "POST",
			headers: {
				...Object.fromEntries(headersObj.entries()),
				"Content-Type": "application/json",
			},
			body: JSON.stringify({
				filename: processedFile.name,
				mimeType: processedFile.type,
				size: processedFile.size,
				folderId,
			}),
		});
		if (!tokenRes.ok) {
			const err = await tokenRes
				.json()
				.catch(() => ({ message: tokenRes.statusText }));
			throw new Error(err.message ?? "Failed to get upload token");
		}

		const token = (await tokenRes.json()) as {
			type: "presigned-url";
			payload: {
				uploadUrl: string;
				publicUrl: string;
				key: string;
				method: "PUT";
				headers: Record<string, string>;
			};
		};

		const putRes = await fetch(token.payload.uploadUrl, {
			method: "PUT",
			headers: token.payload.headers,
			body: processedFile,
		});
		if (!putRes.ok) throw new Error("Failed to upload to S3");

		const assetRes = await fetch(`${base}/media/assets`, {
			method: "POST",
			headers: {
				...Object.fromEntries(headersObj.entries()),
				"Content-Type": "application/json",
			},
			body: JSON.stringify({
				filename: processedFile.name,
				originalName: file.name,
				mimeType: processedFile.type,
				size: processedFile.size,
				url: token.payload.publicUrl,
				folderId,
			}),
		});
		if (!assetRes.ok) {
			const err = await assetRes
				.json()
				.catch(() => ({ message: assetRes.statusText }));
			throw new Error(err.message ?? "Failed to register asset");
		}
		return assetRes.json();
	}

	if (uploadMode === "vercel-blob") {
		// Dynamic import keeps @vercel/blob/client optional.
		const { upload } = await import("@vercel/blob/client");
		const blob = await upload(processedFile.name, processedFile, {
			access: "public",
			handleUploadUrl: `${base}/media/upload/vercel-blob`,
			clientPayload: JSON.stringify({
				mimeType: processedFile.type,
				size: processedFile.size,
			}),
		});

		const assetRes = await fetch(`${base}/media/assets`, {
			method: "POST",
			headers: {
				...Object.fromEntries(headersObj.entries()),
				"Content-Type": "application/json",
			},
			body: JSON.stringify({
				filename: processedFile.name,
				originalName: file.name,
				mimeType: processedFile.type,
				size: processedFile.size,
				url: blob.url,
				folderId,
			}),
		});
		if (!assetRes.ok) {
			const err = await assetRes
				.json()
				.catch(() => ({ message: assetRes.statusText }));
			throw new Error(err.message ?? "Failed to register asset");
		}
		return assetRes.json();
	}

	throw new Error(`Unknown uploadMode: ${uploadMode}`);
}

/**
 * Canvas-based client-side image compression.
 *
 * Skips SVG and GIF (vector data / animation would be lost on a canvas round-trip).
 * All other image/* types are scaled down to fit within maxWidth × maxHeight
 * (preserving aspect ratio) and re-encoded at the configured quality.
 */

export interface ImageCompressionOptions {
	/**
	 * Maximum width in pixels. Images wider than this are scaled down.
	 * @default 2048
	 */
	maxWidth?: number;

	/**
	 * Maximum height in pixels. Images taller than this are scaled down.
	 * @default 2048
	 */
	maxHeight?: number;

	/**
	 * Encoding quality (0–1). Applies to JPEG and WebP.
	 * @default 0.85
	 */
	quality?: number;

	/**
	 * Output MIME type. Defaults to the source image's MIME type.
	 * Set to `"image/webp"` for better compression at the cost of format change.
	 */
	outputFormat?: string;
}

function loadImage(file: File): Promise<HTMLImageElement> {
	return new Promise((resolve, reject) => {
		const url = URL.createObjectURL(file);
		const img = new Image();
		img.onload = () => {
			URL.revokeObjectURL(url);
			resolve(img);
		};
		img.onerror = () => {
			URL.revokeObjectURL(url);
			reject(new Error(`Failed to load image: ${file.name}`));
		};
		img.src = url;
	});
}

const SKIP_TYPES = new Set(["image/svg+xml", "image/gif"]);

/**
 * Compresses an image file client-side using the Canvas API.
 *
 * Returns the original file unchanged if:
 * - The file is not an image
 * - The MIME type is SVG or GIF (would lose vector data / animation)
 * - The browser does not support canvas (SSR guard)
 */
export async function compressImage(
	file: File,
	options: ImageCompressionOptions = {},
): Promise<File> {
	if (!file.type.startsWith("image/") || SKIP_TYPES.has(file.type)) {
		return file;
	}

	// SSR guard — canvas is only available in the browser
	if (typeof document === "undefined") return file;

	const {
		maxWidth = 2048,
		maxHeight = 2048,
		quality = 0.85,
		outputFormat,
	} = options;

	const img = await loadImage(file);

	let { width, height } = img;

	const needsResize = width > maxWidth || height > maxHeight;
	const needsFormatChange =
		outputFormat !== undefined && outputFormat !== file.type;

	// Skip canvas entirely if the image is already within the limits and no
	// format conversion is needed — re-encoding a small image can make it larger.
	if (!needsResize && !needsFormatChange) return file;

	// Scale down proportionally if either dimension exceeds the max
	if (needsResize) {
		const ratio = Math.min(maxWidth / width, maxHeight / height);
		width = Math.round(width * ratio);
		height = Math.round(height * ratio);
	}

	const canvas = document.createElement("canvas");
	canvas.width = width;
	canvas.height = height;

	const ctx = canvas.getContext("2d");
	if (!ctx) return file;

	ctx.drawImage(img, 0, 0, width, height);

	const mimeType = outputFormat ?? file.type;

	return new Promise<File>((resolve, reject) => {
		canvas.toBlob(
			(blob) => {
				if (!blob) {
					reject(new Error("canvas.toBlob returned null"));
					return;
				}

				// Preserve the original filename, updating extension only if
				// the output format changed from the source.
				let name = file.name;
				if (outputFormat && outputFormat !== file.type) {
					const ext = outputFormat.split("/")[1] ?? "jpg";
					name = name.replace(/\.[^.]+$/, `.${ext}`);
				}

				resolve(new File([blob], name, { type: mimeType }));
			},
			mimeType,
			quality,
		);
	});
}

"use client";

import { useEffect } from "react";

/**
 * Base route context interface that plugins can extend
 */
export interface BaseRouteContext {
	/** Current route path */
	path: string;
	/** Route parameters (e.g., { slug: "my-post" }) */
	params?: Record<string, string>;
	/** Whether rendering on server (true) or client (false) */
	isSSR: boolean;
	/** Additional context properties */
	[key: string]: unknown;
}

/**
 * Minimum interface required for route lifecycle hooks
 * Plugin overrides should implement these optional hooks
 */
export interface RouteLifecycleOverrides<TContext extends BaseRouteContext> {
	/** Called when a route is rendered */
	onRouteRender?: (
		routeName: string,
		context: TContext,
	) => void | Promise<void>;
	/** Called when a route encounters an error */
	onRouteError?: (
		routeName: string,
		error: Error,
		context: TContext,
	) => void | Promise<void>;
}

/**
 * Hook to handle route lifecycle events
 * - Calls authorization check before render
 * - Calls onRouteRender on mount
 * - Handles errors with onRouteError
 *
 * @example
 * ```tsx
 * const overrides = usePluginOverrides<MyPluginOverrides>("myPlugin");
 *
 * useRouteLifecycle({
 *   routeName: "dashboard",
 *   context: { path: "/dashboard", isSSR: typeof window === "undefined" },
 *   overrides,
 *   beforeRenderHook: (overrides, context) => {
 *     if (overrides.onBeforeDashboardRendered) {
 *       return overrides.onBeforeDashboardRendered(context);
 *     }
 *     return true;
 *   },
 * });
 * ```
 */
export function useRouteLifecycle<
	TContext extends BaseRouteContext,
	TOverrides extends RouteLifecycleOverrides<TContext>,
>({
	routeName,
	context,
	overrides,
	beforeRenderHook,
}: {
	routeName: string;
	context: TContext;
	overrides: TOverrides;
	beforeRenderHook?: (overrides: TOverrides, context: TContext) => boolean;
}) {
	// Authorization check - runs synchronously before render
	if (beforeRenderHook) {
		const canRender = beforeRenderHook(overrides, context);
		if (!canRender) {
			const error = new Error(`Unauthorized: Cannot render ${routeName}`);
			// Call error hook synchronously
			if (overrides.onRouteError) {
				try {
					const result = overrides.onRouteError(routeName, error, context);
					if (result instanceof Promise) {
						result.catch(() => {}); // Ignore promise rejection
					}
				} catch {
					// Ignore errors in error hook
				}
			}
			throw error;
		}
	}

	// Lifecycle hook - runs on mount
	useEffect(() => {
		if (overrides.onRouteRender) {
			try {
				const result = overrides.onRouteRender(routeName, context);
				if (result instanceof Promise) {
					result.catch((error) => {
						// If onRouteRender throws, call onRouteError
						if (overrides.onRouteError) {
							overrides.onRouteError(routeName, error, context);
						}
					});
				}
			} catch (error) {
				// If onRouteRender throws, call onRouteError
				if (overrides.onRouteError) {
					overrides.onRouteError(routeName, error as Error, context);
				}
			}
		}
	}, [routeName, overrides, context]);
}
